class Solution {
public:
    vector<int> dailyTemperatures(vector<int>& temperatures) {
        int n = temperatures.size();
        stack<int> indices;
        vector<int> result(n, 0);
        int idx = 0;

        for (int i = 0; i < n; ++i) {
            while (!indices.empty() && temperatures[i] > temperatures[indices.top()]) {
                idx = indices.top();
                indices.pop();
                result[idx] = i - idx;
            }
            indices.push(i);
        }
        return result;
    }
};
